ControlPropertyState.AutoRuleBindingString:
// =============================================
// btnCalculateImpact.OnSelect
// Runs on currently selected impact partition
// =============================================

// ── STEP 1: Energy-average L2 across tapper positions ──
ClearCollect(
    col_CalcL2Avg,
    With(
        {
            _l2Rows: Filter(col_MeasurementDisplay, MeasurementType = "L2")
        },
        {
            Hz100: 10 * Log(Average(_l2Rows, Power(10, Hz100 / 10)), 10),
            Hz125: 10 * Log(Average(_l2Rows, Power(10, Hz125 / 10)), 10),
            Hz160: 10 * Log(Average(_l2Rows, Power(10, Hz160 / 10)), 10),
            Hz200: 10 * Log(Average(_l2Rows, Power(10, Hz200 / 10)), 10),
            Hz250: 10 * Log(Average(_l2Rows, Power(10, Hz250 / 10)), 10),
            Hz315: 10 * Log(Average(_l2Rows, Power(10, Hz315 / 10)), 10),
            Hz400: 10 * Log(Average(_l2Rows, Power(10, Hz400 / 10)), 10),
            Hz500: 10 * Log(Average(_l2Rows, Power(10, Hz500 / 10)), 10),
            Hz630: 10 * Log(Average(_l2Rows, Power(10, Hz630 / 10)), 10),
            Hz800: 10 * Log(Average(_l2Rows, Power(10, Hz800 / 10)), 10),
            Hz1000: 10 * Log(Average(_l2Rows, Power(10, Hz1000 / 10)), 10),
            Hz1250: 10 * Log(Average(_l2Rows, Power(10, Hz1250 / 10)), 10),
            Hz1600: 10 * Log(Average(_l2Rows, Power(10, Hz1600 / 10)), 10),
            Hz2000: 10 * Log(Average(_l2Rows, Power(10, Hz2000 / 10)), 10),
            Hz2500: 10 * Log(Average(_l2Rows, Power(10, Hz2500 / 10)), 10),
            Hz3150: 10 * Log(Average(_l2Rows, Power(10, Hz3150 / 10)), 10)
        }
    )
);

// ── STEP 2: Get B2 and average T2 ──
UpdateContext({
    _b2: First(Filter(col_MeasurementDisplay, MeasurementType = "B2")),
    _l2: First(col_CalcL2Avg)
});

ClearCollect(
    col_CalcT2Avg,
    With(
        {
            _t2Rows: Filter(col_MeasurementDisplay, MeasurementType = "T2")
        },
        {
            Hz100: Average(_t2Rows, Hz100),
            Hz125: Average(_t2Rows, Hz125),
            Hz160: Average(_t2Rows, Hz160),
            Hz200: Average(_t2Rows, Hz200),
            Hz250: Average(_t2Rows, Hz250),
            Hz315: Average(_t2Rows, Hz315),
            Hz400: Average(_t2Rows, Hz400),
            Hz500: Average(_t2Rows, Hz500),
            Hz630: Average(_t2Rows, Hz630),
            Hz800: Average(_t2Rows, Hz800),
            Hz1000: Average(_t2Rows, Hz1000),
            Hz1250: Average(_t2Rows, Hz1250),
            Hz1600: Average(_t2Rows, Hz1600),
            Hz2000: Average(_t2Rows, Hz2000),
            Hz2500: Average(_t2Rows, Hz2500),
            Hz3150: Average(_t2Rows, Hz3150)
        }
    )
);

UpdateContext({_t2: First(col_CalcT2Avg)});

// ── STEP 3: Background correction on L2 ──
ClearCollect(
    col_BgCorrection,
    ForAll(
        Table(
            {Freq: "100",  L2Val: _l2.Hz100,  B2Val: _b2.Hz100},
            {Freq: "125",  L2Val: _l2.Hz125,  B2Val: _b2.Hz125},
            {Freq: "160",  L2Val: _l2.Hz160,  B2Val: _b2.Hz160},
            {Freq: "200",  L2Val: _l2.Hz200,  B2Val: _b2.Hz200},
            {Freq: "250",  L2Val: _l2.Hz250,  B2Val: _b2.Hz250},
            {Freq: "315",  L2Val: _l2.Hz315,  B2Val: _b2.Hz315},
            {Freq: "400",  L2Val: _l2.Hz400,  B2Val: _b2.Hz400},
            {Freq: "500",  L2Val: _l2.Hz500,  B2Val: _b2.Hz500},
            {Freq: "630",  L2Val: _l2.Hz630,  B2Val: _b2.Hz630},
            {Freq: "800",  L2Val: _l2.Hz800,  B2Val: _b2.Hz800},
            {Freq: "1000", L2Val: _l2.Hz1000, B2Val: _b2.Hz1000},
            {Freq: "1250", L2Val: _l2.Hz1250, B2Val: _b2.Hz1250},
            {Freq: "1600", L2Val: _l2.Hz1600, B2Val: _b2.Hz1600},
            {Freq: "2000", L2Val: _l2.Hz2000, B2Val: _b2.Hz2000},
            {Freq: "2500", L2Val: _l2.Hz2500, B2Val: _b2.Hz2500},
            {Freq: "3150", L2Val: _l2.Hz3150, B2Val: _b2.Hz3150}
        ) As row,
        With(
            {_diff: row.L2Val - row.B2Val},
            {
                Freq: row.Freq,
                L2Raw: row.L2Val,
                B2Raw: row.B2Val,
                Diff: _diff,
                L2Corrected: If(
                    _diff >= 10,
                    row.L2Val,
                    _diff >= 6,
                    10 * Log(
                        Max(
                            Power(10, row.L2Val / 10) - Power(10, row.B2Val / 10),
                            Power(10, -10)
                        ),
                        10
                    ),
                    row.L2Val - 1.3
                ),
                CorrectionType: If(
                    _diff >= 10, "None",
                    _diff >= 6, "Energy",
                    "Limited"
                )
            }
        )
    )
);

// Pivot back
ClearCollect(
    col_CalcL2Corrected,
    {
        Hz100:  LookUp(col_BgCorrection, Freq = "100").L2Corrected,
        Hz125:  LookUp(col_BgCorrection, Freq = "125").L2Corrected,
        Hz160:  LookUp(col_BgCorrection, Freq = "160").L2Corrected,
        Hz200:  LookUp(col_BgCorrection, Freq = "200").L2Corrected,
        Hz250:  LookUp(col_BgCorrection, Freq = "250").L2Corrected,
        Hz315:  LookUp(col_BgCorrection, Freq = "315").L2Corrected,
        Hz400:  LookUp(col_BgCorrection, Freq = "400").L2Corrected,
        Hz500:  LookUp(col_BgCorrection, Freq = "500").L2Corrected,
        Hz630:  LookUp(col_BgCorrection, Freq = "630").L2Corrected,
        Hz800:  LookUp(col_BgCorrection, Freq = "800").L2Corrected,
        Hz1000: LookUp(col_BgCorrection, Freq = "1000").L2Corrected,
        Hz1250: LookUp(col_BgCorrection, Freq = "1250").L2Corrected,
        Hz1600: LookUp(col_BgCorrection, Freq = "1600").L2Corrected,
        Hz2000: LookUp(col_BgCorrection, Freq = "2000").L2Corrected,
        Hz2500: LookUp(col_BgCorrection, Freq = "2500").L2Corrected,
        Hz3150: LookUp(col_BgCorrection, Freq = "3150").L2Corrected
    }
);

// ── Build after col_CalcT2Avg is populated ──
ClearCollect(
    col_Reverberation,
    ForAll(
        Table(
            {Freq: "100",  FreqSort: 1,  AvgVal: _t2.Hz100},
            {Freq: "125",  FreqSort: 2,  AvgVal: _t2.Hz125},
            {Freq: "160",  FreqSort: 3,  AvgVal: _t2.Hz160},
            {Freq: "200",  FreqSort: 4,  AvgVal: _t2.Hz200},
            {Freq: "250",  FreqSort: 5,  AvgVal: _t2.Hz250},
            {Freq: "315",  FreqSort: 6,  AvgVal: _t2.Hz315},
            {Freq: "400",  FreqSort: 7,  AvgVal: _t2.Hz400},
            {Freq: "500",  FreqSort: 8,  AvgVal: _t2.Hz500},
            {Freq: "630",  FreqSort: 9,  AvgVal: _t2.Hz630},
            {Freq: "800",  FreqSort: 10, AvgVal: _t2.Hz800},
            {Freq: "1000", FreqSort: 11, AvgVal: _t2.Hz1000},
            {Freq: "1250", FreqSort: 12, AvgVal: _t2.Hz1250},
            {Freq: "1600", FreqSort: 13, AvgVal: _t2.Hz1600},
            {Freq: "2000", FreqSort: 14, AvgVal: _t2.Hz2000},
            {Freq: "2500", FreqSort: 15, AvgVal: _t2.Hz2500},
            {Freq: "3150", FreqSort: 16, AvgVal: _t2.Hz3150}
        ) As row,
        With(
            {
                _t2Rows: Filter(col_MeasurementDisplay, MeasurementType = "T2"),
                _freqField: Switch(
                    row.Freq,
                    "100", "Hz100", "125", "Hz125", "160", "Hz160",
                    "200", "Hz200", "250", "Hz250", "315", "Hz315",
                    "400", "Hz400", "500", "Hz500", "630", "Hz630",
                    "800", "Hz800", "1000", "Hz1000", "1250", "Hz1250",
                    "1600", "Hz1600", "2000", "Hz2000", "2500", "Hz2500",
                    "3150", "Hz3150"
                )
            },
            {
                Freq: row.Freq,
                FreqSort: row.FreqSort,
                DisplayFreq: Switch(
                    row.Freq,
                    "1000", "1k", "1250", "1.25k", "1600", "1.6k",
                    "2000", "2k", "2500", "2.5k", "3150", "3.15k",
                    row.Freq
                ) & "Hz",
                T2Avg: Round(row.AvgVal, 2),
                RTCorrection: Round(10 * Log(row.AvgVal / 0.5, 10), 2),
                ReadingCount: CountRows(_t2Rows),
                MinVal: Round(
                    Min(_t2Rows,
                        Switch(row.Freq,
                            "100", Hz100, "125", Hz125, "160", Hz160,
                            "200", Hz200, "250", Hz250, "315", Hz315,
                            "400", Hz400, "500", Hz500, "630", Hz630,
                            "800", Hz800, "1000", Hz1000, "1250", Hz1250,
                            "1600", Hz1600, "2000", Hz2000, "2500", Hz2500,
                            "3150", Hz3150
                        )
                    ), 2
                ),
                MaxVal: Round(
                    Max(_t2Rows,
                        Switch(row.Freq,
                            "100", Hz100, "125", Hz125, "160", Hz160,
                            "200", Hz200, "250", Hz250, "315", Hz315,
                            "400", Hz400, "500", Hz500, "630", Hz630,
                            "800", Hz800, "1000", Hz1000, "1250", Hz1250,
                            "1600", Hz1600, "2000", Hz2000, "2500", Hz2500,
                            "3150", Hz3150
                        )
                    ), 2
                ),
                Spread: Round(
                    Max(_t2Rows,
                        Switch(row.Freq,
                            "100", Hz100, "125", Hz125, "160", Hz160,
                            "200", Hz200, "250", Hz250, "315", Hz315,
                            "400", Hz400, "500", Hz500, "630", Hz630,
                            "800", Hz800, "1000", Hz1000, "1250", Hz1250,
                            "1600", Hz1600, "2000", Hz2000, "2500", Hz2500,
                            "3150", Hz3150
                        )
                    )
                    -
                    Min(_t2Rows,
                        Switch(row.Freq,
                            "100", Hz100, "125", Hz125, "160", Hz160,
                            "200", Hz200, "250", Hz250, "315", Hz315,
                            "400", Hz400, "500", Hz500, "630", Hz630,
                            "800", Hz800, "1000", Hz1000, "1250", Hz1250,
                            "1600", Hz1600, "2000", Hz2000, "2500", Hz2500,
                            "3150", Hz3150
                        )
                    ), 2
                ),
                StandardisedTo: 0.5
            }
        )
    )
);

// Free flags
UpdateContext({
    _bgCorrectionApplied: CountRows(Filter(col_BgCorrection, CorrectionType = "Energy")) > 0,
    _limitedByBackground: CountRows(Filter(col_BgCorrection, CorrectionType = "Limited")) > 0
});

UpdateContext({_l2c: First(col_CalcL2Corrected)});

// ── STEP 4: Calculate L'nT per frequency ──
// L'nT = Li - 10*log10(T/T0) where T0 = 0.5
// Note: SUBTRACT the RT correction (opposite to airborne DnT)
ClearCollect(
    col_CalcLnT,
    {
        Hz100: _l2c.Hz100 - 10 * Log(_t2.Hz100 / 0.5, 10),
        Hz125: _l2c.Hz125 - 10 * Log(_t2.Hz125 / 0.5, 10),
        Hz160: _l2c.Hz160 - 10 * Log(_t2.Hz160 / 0.5, 10),
        Hz200: _l2c.Hz200 - 10 * Log(_t2.Hz200 / 0.5, 10),
        Hz250: _l2c.Hz250 - 10 * Log(_t2.Hz250 / 0.5, 10),
        Hz315: _l2c.Hz315 - 10 * Log(_t2.Hz315 / 0.5, 10),
        Hz400: _l2c.Hz400 - 10 * Log(_t2.Hz400 / 0.5, 10),
        Hz500: _l2c.Hz500 - 10 * Log(_t2.Hz500 / 0.5, 10),
        Hz630: _l2c.Hz630 - 10 * Log(_t2.Hz630 / 0.5, 10),
        Hz800: _l2c.Hz800 - 10 * Log(_t2.Hz800 / 0.5, 10),
        Hz1000: _l2c.Hz1000 - 10 * Log(_t2.Hz1000 / 0.5, 10),
        Hz1250: _l2c.Hz1250 - 10 * Log(_t2.Hz1250 / 0.5, 10),
        Hz1600: _l2c.Hz1600 - 10 * Log(_t2.Hz1600 / 0.5, 10),
        Hz2000: _l2c.Hz2000 - 10 * Log(_t2.Hz2000 / 0.5, 10),
        Hz2500: _l2c.Hz2500 - 10 * Log(_t2.Hz2500 / 0.5, 10),
        Hz3150: _l2c.Hz3150 - 10 * Log(_t2.Hz3150 / 0.5, 10)
    }
);

UpdateContext({_lnt: First(col_CalcLnT)});

// ── STEP 5: ISO 717-2 curve fitting ──
// Impact reference curve (higher = worse)
ClearCollect(
    col_ISORefImpact,
    {Hz100: 62, Hz125: 62, Hz160: 62, Hz200: 62, Hz250: 62, Hz315: 62,
     Hz400: 61, Hz500: 60, Hz630: 59, Hz800: 58, Hz1000: 57, Hz1250: 54,
     Hz1600: 51, Hz2000: 48, Hz2500: 45, Hz3150: 42}
);

UpdateContext({_ref: First(col_ISORefImpact)});

// Try shifts from -30 to +20 in 1dB steps
// For impact: unfavourable = measured EXCEEDS shifted reference
// Find the LOWEST shift where sum of unfavourable deviations <= 32
ClearCollect(
    col_ShiftResults,
    ForAll(
        Sequence(51, -30) As shift,
        With(
            {
                _devSum:
                    Max(0, _lnt.Hz100 - (_ref.Hz100 + shift.Value)) +
                    Max(0, _lnt.Hz125 - (_ref.Hz125 + shift.Value)) +
                    Max(0, _lnt.Hz160 - (_ref.Hz160 + shift.Value)) +
                    Max(0, _lnt.Hz200 - (_ref.Hz200 + shift.Value)) +
                    Max(0, _lnt.Hz250 - (_ref.Hz250 + shift.Value)) +
                    Max(0, _lnt.Hz315 - (_ref.Hz315 + shift.Value)) +
                    Max(0, _lnt.Hz400 - (_ref.Hz400 + shift.Value)) +
                    Max(0, _lnt.Hz500 - (_ref.Hz500 + shift.Value)) +
                    Max(0, _lnt.Hz630 - (_ref.Hz630 + shift.Value)) +
                    Max(0, _lnt.Hz800 - (_ref.Hz800 + shift.Value)) +
                    Max(0, _lnt.Hz1000 - (_ref.Hz1000 + shift.Value)) +
                    Max(0, _lnt.Hz1250 - (_ref.Hz1250 + shift.Value)) +
                    Max(0, _lnt.Hz1600 - (_ref.Hz1600 + shift.Value)) +
                    Max(0, _lnt.Hz2000 - (_ref.Hz2000 + shift.Value)) +
                    Max(0, _lnt.Hz2500 - (_ref.Hz2500 + shift.Value)) +
                    Max(0, _lnt.Hz3150 - (_ref.Hz3150 + shift.Value))
            },
            {
                Shift: shift.Value,
                DevSum: _devSum,
                Passes: _devSum <= 32
            }
        )
    )
);

// L'nT,w = 500Hz reference + lowest passing shift
UpdateContext({
    _bestShift: Min(Filter(col_ShiftResults, Passes), Shift)
});

UpdateContext({
    _LnTw: _ref.Hz500 + _bestShift
});

// ── STEP 6: Pass/Fail ──
// Impact: LOWER is better, so pass = measured <= required
UpdateContext({
    _result: If(
        _LnTw <= cVar_CurrentPartition.RequiredValue,
        "Pass",
        "Fail"
    )
});

// ── STEP 7: Save results ──
Patch(
    BESA_TestRuns,
    LookUp(BESA_TestRuns, BESA_TestRun = cVar_CurrentPartition.PartitionID),
    {
        SummaryResults: JSON(
            {
                LnTw: _LnTw,
                RequiredValue: cVar_CurrentPartition.RequiredValue,
                Result: _result,
                LnTSpectral: {
                    '100': Round(_lnt.Hz100, 1), '125': Round(_lnt.Hz125, 1),
                    '160': Round(_lnt.Hz160, 1), '200': Round(_lnt.Hz200, 1),
                    '250': Round(_lnt.Hz250, 1), '315': Round(_lnt.Hz315, 1),
                    '400': Round(_lnt.Hz400, 1), '500': Round(_lnt.Hz500, 1),
                    '630': Round(_lnt.Hz630, 1), '800': Round(_lnt.Hz800, 1),
                    '1000': Round(_lnt.Hz1000, 1), '1250': Round(_lnt.Hz1250, 1),
                    '1600': Round(_lnt.Hz1600, 1), '2000': Round(_lnt.Hz2000, 1),
                    '2500': Round(_lnt.Hz2500, 1), '3150': Round(_lnt.Hz3150, 1)
                }
            }
        )
    }
);

// ── STEP 8: Update collection ──
UpdateIf(
    col_AcousticPartitions,
    PartitionID = cVar_CurrentPartition.PartitionID,
    {
        LnTw: _LnTw,
        PassFail: _result
    }
);

// ── STEP 9: Refresh display ──
Select(btnRefreshMeasurements_2);

Notify(
    "L'nT,w = " & Text(_LnTw) & " dB"
    & "  |  Required: ≤" & Text(cVar_CurrentPartition.RequiredValue) & " dB"
    & "  |  " & _result,
    If(_result = "Pass", NotificationType.Success, NotificationType.Error)
);

Patch(
    BESA_Tests,
    LookUp(BESA_Tests, BESA_Test = varActionRecord.BESA_Test),
    {
        'Section Status': JSON(
            {
                TestDetails:  Text(varSectionStatus.TestDetails),
                Envelope:     Text(varSectionStatus.Envelope),
                ReportExport: "Complete"
            }
        ),
        'Test Status': "Pending Completion"
    }
);


Patch(
    BESA_BookingElements,
    LookUp(BESA_BookingElements, BESA_BookingElement = varActionRecord.'Booking Element LookUp'.BESA_BookingElement),
    {
        'Booking Element Status': "Pending Completion"
    }
);



Patch(BESA_Documents,
    Defaults(BESA_Documents),
    {
        'Document Image': penRAMSSignOff_4.Image,
        'Direct Related GUID': varActionRecord.BESA_Test,
        'Document Type': "Test Report"
    }
);
   With(
      {
          wthSingle: LookUp(col_TestRun, RunSelected = true).SummaryResults.Results,
          wthD:      LookUp(col_TestRun, RunSelected = true && Text(TestMetaData.TestType) =
  "Depressurisation").SummaryResults.Results,
          wthP:      LookUp(col_TestRun, RunSelected = true && Text(TestMetaData.TestType) =
  "Pressurisation").SummaryResults.Results
      },
      Patch(
          BESA_Tests,
          LookUp(BESA_Tests, BESA_Test = varActionRecord.BESA_Test),
          {
              'Test JSON': If(
                  varServiceTestType = "Plenum Test"
                  || varServiceTestType = "PassivHaus Test"
                  || varServiceTestType = "Isolation Room Air Test",

                  // 2-run tests — save Depress, Press and computed Result
                  JSON({
                      Depressurisation: {
                          AP50: Value(wthD.AP50),
                          Q50:  Value(wthD.Q50),
                          ELA:  Value(wthD.ELA),
                          R2:   Value(wthD.R2),
                          Exp:  Value(wthD.Exp),
                          Cenv: Value(wthD.Cenv),
                          CL:   Value(wthD.CL)
                      },
                      Pressurisation: {
                          AP50: Value(wthP.AP50),
                          Q50:  Value(wthP.Q50),
                          ELA:  Value(wthP.ELA),
                          R2:   Value(wthP.R2),
                          Exp:  Value(wthP.Exp),
                          Cenv: Value(wthP.Cenv),
                          CL:   Value(wthP.CL)
                      },
                      Result: {
                          AP50: Round(If(varServiceTestType = "Plenum Test", Value(wthD.AP50) - Value(wthP.AP50),
  (Value(wthD.AP50) + Value(wthP.AP50)) / 2), 2),
                          Q50:  Round(If(varServiceTestType = "Plenum Test", Value(wthD.Q50)  - Value(wthP.Q50),
  (Value(wthD.Q50)  + Value(wthP.Q50))  / 2), 2),
                          ELA:  Round(If(varServiceTestType = "Plenum Test", Value(wthD.ELA)  - Value(wthP.ELA),
  (Value(wthD.ELA)  + Value(wthP.ELA))  / 2), 2),
                          R2:   Round(If(varServiceTestType = "Plenum Test", Value(wthD.R2)   - Value(wthP.R2),
  (Value(wthD.R2)   + Value(wthP.R2))   / 2), 2),
                          Exp:  Round(If(varServiceTestType = "Plenum Test", Value(wthD.Exp)  - Value(wthP.Exp),
  (Value(wthD.Exp)  + Value(wthP.Exp))  / 2), 2),
                          Cenv: Round(If(varServiceTestType = "Plenum Test", Value(wthD.Cenv) - Value(wthP.Cenv),
  (Value(wthD.Cenv) + Value(wthP.Cenv)) / 2), 2),
                          CL:   Round(If(varServiceTestType = "Plenum Test", Value(wthD.CL)   - Value(wthP.CL),
  (Value(wthD.CL)   + Value(wthP.CL))   / 2), 2)
                      }
                  }),

                  // Single run — Air Test, Smoke Shaft, Air Permeability
                  JSON({
                      AP50: Value(wthSingle.AP50),
                      Q50:  Value(wthSingle.Q50),
                      ELA:  Value(wthSingle.ELA),
                      R2:   Value(wthSingle.R2),
                      Exp:  Value(wthSingle.Exp),
                      Cenv: Value(wthSingle.Cenv),
                      CL:   Value(wthSingle.CL)
                  })
              )
          }
      )
  );

UpdateIf(
    col_EngineerActionList,
    'Booking Element LookUp'.BESA_BookingElement = varActionRecord.'Booking Element LookUp'.BESA_BookingElement,
    {
        'Action Status': "Complete"
    }
);

UpdateIf(
    col_ShiftTimeline,
    'Booking Element LookUp'.BESA_BookingElement = varActionRecord.'Booking Element LookUp'.BESA_BookingElement &&
    (IsBlank(TestNumber) || TestNumber <= 1),
    {
        'Action Status': "Complete"
    }
);

Set(
    varSectionStatus,
    ParseJSON(
        JSON(
            {
                TestDetails:  Text(varSectionStatus.TestDetails),
                Envelope:     Text(varSectionStatus.Envelope),
                ReportExport: "Complete"
            }
        )
    )
);

UpdateIf(
    col_PermTestMenu,
    MenuCategory = "Report & Export",
    {
        Status:       "Complete",
        DisplayLabel: "Report & Export ✓"
    }
);

Notify("Test marked as complete", NotificationType.Success);

Reset(checkConfirm_4);
Reset(penRAMSSignOff_4);
Set(varCompleteServicePopup, false);

// =============================================
// STEP 1 — Save Partition Details
// =============================================

Select(ButtonTestChecks_1);

Patch(
    BESA_TestRuns,
    LookUp(BESA_TestRuns, BESA_TestRun = cVar_CurrentPartition.TestRunID),
    {
        // ── Partition definition ──
        PartitionData: JSON(
            {
                PartitionLabel: Text(cVar_CurrentPartition.PartitionLabel),
                TestReportNumber: txtTestReportNumber_1.Text,
                TestCategory: drpTestCategory_1.Selected.Value,
                PartitionType: drpPartitionType_1.Selected.Value,
                ConstructionType: txtConstructionType.Text,
                SourceRoom: txtSourceRoom_3.Text,
                ReceiverRoom: txtReceiverRoom_1.Text,
                SourceRoomVolume: Value(txtSourceRoomVolume_1.Text),
                ReceiverRoomVolume: Value(txtReceiverRoomVolume_1.Text),
                SeparatingElementArea: Value(txtElementArea.Text),
                MetricToReport: If(
                    drpTestCategory_1.Selected.Value = "Impact",
                    "L'nT,w",
                    "DnT,w + Ctr"
                ),
                RequiredValue: With(
                    {
                        _buildType: LookUp(
                            Table(
                                {Key: "Purpose built dwelling houses and flats", AirborneMin: 45, ImpactMax: 62},
                                {Key: "Dwelling houses and flats formed by material change of use", AirborneMin: 43, ImpactMax: 64}
                            ),
                            Key = Text(varTestInfo.BuildType)
                        ),
                        _enhancement: Value(Text(varTestInfo.Enhancement))
